/* dbo.MAHALLELER - UTF-8, sqlcmd -f 65001 */
SET NOCOUNT ON;
GO

IF OBJECT_ID(N'dbo.MAHALLELER', N'U') IS NULL RETURN;
IF NOT EXISTS (SELECT 1 FROM [dbo].[ILCELER]) RETURN;
GO

IF OBJECT_ID('tempdb..#mahalle_seed') IS NOT NULL DROP TABLE #mahalle_seed;
CREATE TABLE #mahalle_seed (
    API_KODU int NOT NULL PRIMARY KEY,
    PLAKA smallint NOT NULL,
    ILCE_API int NOT NULL,
    MAHALLE_ADI nvarchar(120) NOT NULL,
    SEO_SLUG nvarchar(180) NOT NULL,
    POSTA_KODU nvarchar(10) NULL
);
GO













































































































GO

MERGE [dbo].[MAHALLELER] AS t
USING (
    SELECT
        i.[ID] AS IL_ID,
        c.[ID] AS ILCE_ID,
        s.[API_KODU], s.[MAHALLE_ADI], s.[SEO_SLUG], s.[POSTA_KODU]
    FROM #mahalle_seed s
    INNER JOIN [dbo].[ILLER] i ON i.[PLAKA_KODU] = s.[PLAKA]
    INNER JOIN [dbo].[ILCELER] c ON c.[API_KODU] = s.[ILCE_API]
) AS s ON t.[API_KODU] = s.[API_KODU]
WHEN MATCHED THEN UPDATE SET
    [IL_ID]=s.[IL_ID],[ILCE_ID]=s.[ILCE_ID],[MAHALLE_ADI]=s.[MAHALLE_ADI],
    [SEO_SLUG]=s.[SEO_SLUG],[POSTA_KODU]=s.[POSTA_KODU],
    [AKTIF_MI]=1,[GUNCELLENME_TARIHI]=sysutcdatetime()
WHEN NOT MATCHED THEN INSERT ([IL_ID],[ILCE_ID],[API_KODU],[MAHALLE_ADI],[SEO_SLUG],[POSTA_KODU],[AKTIF_MI])
    VALUES (s.[IL_ID],s.[ILCE_ID],s.[API_KODU],s.[MAHALLE_ADI],s.[SEO_SLUG],s.[POSTA_KODU],1);
GO
-- 32254 mahalle
